import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import UserProfile from "../../components/UserProfile/UserProfile";
import { workoutsService } from "../../services/workouts.service";
import { coursesService } from "../../services/courses.service";
import styles from "./TrainingPage.module.css";

interface Exercise {
  _id: string;
  name: string;
  quantity: number;
  progress?: number;
}

interface TrainingPageProps {
  userName?: string;
  userEmail?: string;
  token?: string;
  onLogout?: () => void;
}

const TrainingPage: React.FC<TrainingPageProps> = ({
  userName = "",
  userEmail = "",
  token,
  onLogout,
}) => {
  const navigate = useNavigate();
  const { id } = useParams<{ id: string }>();
  const [exercises, setExercises] = useState<Exercise[]>([]);
  const [workoutName, setWorkoutName] = useState("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (token && id) {
      loadWorkoutData();
    }
  }, [token, id]);

  const loadWorkoutData = async () => {
    if (!token || !id) return;

    try {
      setLoading(true);
      // Получаем данные тренировки
      const workout = await workoutsService.getWorkoutById(id, token);
      setWorkoutName(workout.name);

      // Получаем прогресс по этой тренировке
      // TODO: Нужно передавать courseId
      // const progress = await workoutsService.getWorkoutProgress(courseId, id, token);

      const exercisesWithProgress = workout.exercises.map((ex, index) => ({
        ...ex,
        progress: 0, // progress?.progressData[index] || 0
      }));

      setExercises(exercisesWithProgress);
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Ошибка загрузки тренировки",
      );
    } finally {
      setLoading(false);
    }
  };

  const handleProfileClick = () => {
    navigate("/profile");
  };

  const handleAddCourse = () => {
    navigate("/courses");
  };

  const handleOpenProgress = () => {
    navigate(`/training/${id}/progress`);
  };

  const calculateProgress = (exercise: Exercise) => {
    return exercise.quantity > 0
      ? Math.round(((exercise.progress || 0) / exercise.quantity) * 100)
      : 0;
  };

  if (loading) return <div className={styles.loading}>Загрузка...</div>;
  if (error) return <div className={styles.error}>{error}</div>;

  return (
    <div className={styles.page}>
      <img
        src={`${process.env.PUBLIC_URL}/images/logo.svg`}
        alt="SkyFitnessPro"
        className={styles.logo}
      />

      <div className={styles.userProfileWrapper}>
        <UserProfile
          userName={userName}
          userEmail={userEmail}
          token={token}
          onProfileClick={handleProfileClick}
          onLogout={onLogout}
          onAddCourse={handleAddCourse}
        />
      </div>

      <div className={styles.contentBlock}>
        <h1 className={styles.title}>{workoutName || "Тренировка"}</h1>

        <div className={styles.videoContainer}>
          <img
            src={`${process.env.PUBLIC_URL}/images/vid1.svg`}
            alt="Video"
            className={styles.videoImage}
          />
        </div>

        <div className={styles.exercisesBlock}>
          <div className={styles.exercisesContent}>
            <h2 className={styles.exercisesTitle}>Упражнения тренировки</h2>

            <div className={styles.exercisesGrid}>
              {/* Разбиваем упражнения на 3 колонки */}
              {[0, 1, 2].map((colIndex) => (
                <div key={colIndex} className={styles.exerciseColumn}>
                  {exercises
                    .slice(colIndex * 3, colIndex * 3 + 3)
                    .map((exercise) => (
                      <div key={exercise._id} className={styles.exerciseItem}>
                        <p className={styles.exerciseText}>
                          {exercise.name} {calculateProgress(exercise)}%
                        </p>
                        <div className={styles.progressBarBg}>
                          <div
                            className={styles.progressBarFill}
                            style={{ width: `${calculateProgress(exercise)}%` }}
                          />
                        </div>
                      </div>
                    ))}
                </div>
              ))}
            </div>

            <button
              className={styles.progressButton}
              onClick={handleOpenProgress}
            >
              Заполнить свой прогресс
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TrainingPage;
